class Solution:
    def maxScore(self, nums):
        import itertools
        best = 0
        for perm in itertools.permutations(nums):
            total = 0
            score = 0
            for v in perm:
                total += v
                if total > 0:
                    score += 1
            best = max(best, score)
        return best

